SELECT name
FROM business_entities
WHERE status = 'Active' AND industry = 'Finance';

SELECT COUNT(*) AS active_finance_entities
FROM business_entities
WHERE status = 'Active' AND industry = 'Finance';

SELECT name
FROM business_entities
WHERE status = 'Active' AND industry = 'Finance' AND num_employees > 50;

SELECT name
FROM business_entities
ORDER BY name;

SELECT COUNT(person_id) 
FROM key_people 
WHERE entity_id = 0 AND is_current = 1;
